#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int Li, Ri, Lj, Rj;
        scanf("%d %d", &Li, &Ri);
        int operations = 0;
        char sequence[10000] = "";
        for (int i = 1; i < N; i++) {
            scanf("%d %d", &Lj, &Rj);
            while (Li < Lj) {
                Li++;
                operations++;
                strcat(sequence, "L+");
            }
            while (Li > Lj) {
                Li--;
                operations++;
                strcat(sequence, "L-");
            }
            while (Ri < Rj) {
                Ri++;
                operations++;
                strcat(sequence, "R+");
            }
            while (Ri > Rj) {
                Ri--;
                operations++;
                strcat(sequence, "R-");
            }
        }
        printf("%d\n", operations);
        printf("%s\n", sequence);
    }
    return 0;
}

